import type {
  ListContentProps,
  ListDescriptionProps,
  ListRootProps,
  ListTitleProps,
  ListUi,
  ListItemProps as _ListItemProps
} from '@soybeanjs/headless/list';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the List component.
 */
export interface ListProps extends ListRootProps {
  /**
   * Additional class names applied to the root element.
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<ListUi>;
}

/**
 * Properties for the ListItem component.
 */
export interface ListItemProps extends _ListItemProps {
  /**
   * Title text rendered by the component.
   */
  title?: string;
  /**
   * Description text rendered by the component.
   */
  description?: string;
  /**
   * Properties forwarded to the content element.
   */
  contentProps?: ListContentProps;
  /**
   * Properties forwarded to the title element.
   */
  titleProps?: ListTitleProps;
  /**
   * Properties forwarded to the description element.
   */
  descriptionProps?: ListDescriptionProps;
}

export { default as SList } from './list.vue';
export { default as SListItem } from './list-item.vue';

export type {
  ListRootProps,
  ListContentProps,
  ListTitleProps,
  ListDescriptionProps,
  ListUiSlot,
  ListUi
} from '@soybeanjs/headless/list';
export type * from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const listVariants = scv({
  slots: {
    root: 'flex flex-col',
    item: 'flex list-none',
    content: 'grow flex flex-col',
    title: 'font-medium tracking-tight m-0',
    description: '[&_p]:leading-relaxed text-muted-foreground m-0'
  },
  variants: {
    size: {
      xs: {
        root: 'gap-2 text-2xs',
        item: 'gap-2',
        content: 'gap-0.75',
        title: 'text-xs leading-3.125'
      },
      sm: {
        root: 'gap-3 text-xs',
        item: 'gap-3',
        content: 'gap-1',
        title: 'text-sm leading-3.75'
      },
      md: {
        root: 'gap-4 text-sm',
        item: 'gap-4',
        content: 'gap-1',
        title: 'text-base leading-4.375'
      },
      lg: {
        root: 'gap-5 text-base',
        item: 'gap-5',
        content: 'gap-1.25',
        title: 'text-lg leading-5'
      },
      xl: {
        root: 'gap-6 text-lg',
        item: 'gap-6',
        content: 'gap-1.5',
        title: 'text-xl leading-5.625'
      },
      '2xl': {
        root: 'gap-7 text-xl',
        item: 'gap-7',
        content: 'gap-2',
        title: 'text-2xl leading-6.25'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
